import{_ as t,o,c as r,a2 as s}from"./chunks/framework.il0noOp3.js";const m=JSON.parse('{"title":"Required Permissions","description":"ARM RBAC and Microsoft Graph permissions required by AzureScout.","frontmatter":{"description":"ARM RBAC and Microsoft Graph permissions required by AzureScout."},"headers":[],"relativePath":"permissions.md","filePath":"permissions.md"}'),i={name:"permissions.md"};function a(d,e,n,c,l,p){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="required-permissions" tabindex="-1">Required Permissions <a class="header-anchor" href="#required-permissions" aria-label="Permalink to &quot;Required Permissions&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">This page covers the v1 inventory tool</p><p>This page describes the permission model for the <strong>v1 inventory cmdlet</strong> (<code>Invoke-AzureScout</code> / <code>Test-AZSCPermissions</code>). The <strong>CAF/WAF assessment platform</strong> (<code>Invoke-ScoutAssessment</code> / <code>Test-ScoutPermission</code>) uses a different, narrower model — see the note at the bottom of this page, or go straight to <a href="./assessment-permissions.html">Assessment Permissions</a>. Not sure which tool you need? See <a href="./overview.html">Overview: Inventory vs Assessment</a>.</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>AzureScout requires two categories of permissions:</p><ol><li><strong>ARM (Azure Resource Manager)</strong> — RBAC role assignments on subscriptions</li><li><strong>Microsoft Graph API</strong> — Application or delegated permissions for Entra ID data</li></ol><h2 id="arm-permissions" tabindex="-1">ARM Permissions <a class="header-anchor" href="#arm-permissions" aria-label="Permalink to &quot;ARM Permissions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Permission</th><th>Scope</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Reader</code></td><td>Subscription(s)</td><td>Enumerate resources, read properties</td></tr><tr><td><code>Reader</code> on role assignments</td><td>Subscription(s)</td><td>Read RBAC role assignments (optional — Warn if missing)</td></tr></tbody></table><p>The pre-flight checker validates:</p><ul><li><strong>Subscription Enumeration</strong> — Can <code>Get-AzSubscription</code> return at least one subscription? (Fail if not)</li><li><strong>Role Assignment Read</strong> — Can <code>Get-AzRoleAssignment</code> read roles on the first subscription? (Warn if not — non-blocking)</li></ul><h2 id="microsoft-graph-permissions" tabindex="-1">Microsoft Graph Permissions <a class="header-anchor" href="#microsoft-graph-permissions" aria-label="Permalink to &quot;Microsoft Graph Permissions&quot;">​</a></h2><p>The following Microsoft Graph API permissions are required for Entra ID inventory:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Organization.Read.All</code></td><td>Application or Delegated</td><td>Read tenant organization details</td></tr><tr><td><code>User.Read.All</code></td><td>Application or Delegated</td><td>Read all user profiles</td></tr><tr><td><code>Group.Read.All</code></td><td>Application or Delegated</td><td>Read all groups and memberships</td></tr><tr><td><code>Application.Read.All</code></td><td>Application or Delegated</td><td>Read all app registrations and service principals</td></tr><tr><td><code>Directory.Read.All</code></td><td>Application or Delegated</td><td>Read directory roles, administrative units, domains</td></tr><tr><td><code>Policy.Read.All</code></td><td>Application or Delegated</td><td>Read conditional access policies, named locations</td></tr><tr><td><code>RoleManagement.Read.All</code></td><td>Application or Delegated</td><td>Read PIM role assignments and eligible assignments</td></tr><tr><td><code>IdentityProvider.Read.All</code></td><td>Application or Delegated</td><td>Read authentication methods and identity providers</td></tr><tr><td><code>Policy.Read.ConditionalAccess</code></td><td>Application or Delegated</td><td>Read conditional access policies (optional — Warn only)</td></tr></tbody></table><h2 id="pre-flight-validation" tabindex="-1">Pre-flight Validation <a class="header-anchor" href="#pre-flight-validation" aria-label="Permalink to &quot;Pre-flight Validation&quot;">​</a></h2><p>The <code>Test-AZSCPermissions</code> function runs automatically before extraction (unless <code>-SkipPermissionCheck</code> is set):</p><table tabindex="0"><thead><tr><th>Check</th><th>Severity</th><th>Behavior</th></tr></thead><tbody><tr><td>ARM: Subscription Enumeration</td><td><strong>Fail</strong></td><td>Stops ARM extraction if no subscriptions accessible</td></tr><tr><td>ARM: Role Assignment Read</td><td><strong>Warn</strong></td><td>Continues — some RBAC data may be missing</td></tr><tr><td>Graph: Organization Read</td><td><strong>Fail</strong></td><td>Stops Entra extraction if organization endpoint is inaccessible</td></tr><tr><td>Graph: User Read</td><td><strong>Fail</strong></td><td>Stops Entra extraction if user endpoint is inaccessible</td></tr><tr><td>Graph: Conditional Access Policies</td><td><strong>Warn</strong></td><td>Continues — CA policy data may be missing</td></tr></tbody></table><h2 id="scope-based-gating" tabindex="-1">Scope-Based Gating <a class="header-anchor" href="#scope-based-gating" aria-label="Permalink to &quot;Scope-Based Gating&quot;">​</a></h2><p>Permission checks respect the <code>-Scope</code> parameter:</p><ul><li><code>ArmOnly</code> — Only ARM checks run (Graph checks are skipped entirely)</li><li><code>EntraOnly</code> — Only Graph checks run (ARM checks are skipped entirely)</li><li><code>All</code> — Both ARM and Graph checks run</li></ul><h2 id="remediation" tabindex="-1">Remediation <a class="header-anchor" href="#remediation" aria-label="Permalink to &quot;Remediation&quot;">​</a></h2><p>If the permission checker reports failures:</p><ol><li>For ARM: Ensure <code>Reader</code> role is assigned on target subscriptions</li><li>For Graph: Grant the required Microsoft Graph API permissions to your app registration or user account</li><li>Re-run with the appropriate credentials</li></ol><h2 id="a-different-narrower-model-for-the-caf-waf-assessment-platform" tabindex="-1">A different, narrower model for the CAF/WAF assessment platform <a class="header-anchor" href="#a-different-narrower-model-for-the-caf-waf-assessment-platform" aria-label="Permalink to &quot;A different, narrower model for the CAF/WAF assessment platform&quot;">​</a></h2><p>Everything above is the <strong>v1 inventory</strong> permission model (<code>Invoke-AzureScout</code> / <code>Test-AZSCPermissions</code>). The v2 <strong>assessment platform</strong> (<code>Invoke-ScoutAssessment</code> / <code>Test-ScoutPermission</code>) uses a different, narrower model — do not conflate the two:</p><table tabindex="0"><thead><tr><th></th><th>v1 inventory (<code>Test-AZSCPermissions</code>)</th><th>v2 assessment (<code>Test-ScoutPermission</code>)</th></tr></thead><tbody><tr><td>ARM scope</td><td><code>Reader</code> on each target <strong>subscription</strong></td><td><code>Reader</code> at the <strong>tenant-root management group</strong></td></tr><tr><td>Graph</td><td>Up to 9 permissions, required for <code>-Scope All</code>/<code>EntraOnly</code></td><td>4 permissions, required <strong>only</strong> for the 5 assessments that ingest AzGovViz (<code>LandingZone</code>, <code>Management</code>, <code>Identity</code>, <code>Governance</code>, <code>Policy</code>)</td></tr><tr><td>Live-validated?</td><td>Yes — both ARM and Graph checks call live endpoints</td><td>ARM check is live; the 4 Graph permissions are listed as an <strong>unverified checklist</strong> (<code>Ok = $null</code>), not actually tested</td></tr></tbody></table><p>Full matrix (every assessment, minimum RBAC, which need Graph, and the <code>PrivilegedAccess.Read.AzureResources</code> / Entra P2 nuance): <a href="./assessment-permissions.html">Auth &amp; permissions per scan type</a>.</p>',25)])])}const u=t(i,[["render",a]]);export{m as __pageData,u as default};
